BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?elem ?name ?type WHERE {
  BIND(<http://api.koneksys.com/cameo/TMT/package/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::10%2520Analysis::Roll-up%2520Analyses::Dynamic%2520Power%2520Analysis::05%2520Simulation%2520Configurations> AS ?pkg)
  ?pkg vocab:Element_ownedElement+ ?elem .
  ?elem rdf:type ?type .
  OPTIONAL { ?elem vocab:NamedElement_name ?name . }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?inst ?name ?classifierName WHERE {
  BIND(<http://api.koneksys.com/cameo/TMT/package/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::10%2520Analysis::Roll-up%2520Analyses::Dynamic%2520Power%2520Analysis::05%2520Simulation%2520Configurations> AS ?pkg)

  ?pkg vocab:Element_ownedElement+ ?inst .
  ?inst rdf:type vocab:instance%20specification .

  OPTIONAL { ?inst vocab:NamedElement_name ?name . }
  OPTIONAL {
    ?inst vocab:InstanceSpecification_classifier ?cls .
    ?cls vocab:NamedElement_name ?classifierName .
  }
}
ORDER BY LCASE(STR(?name))
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?inst ?instName ?spec ?specName ?slotValueName WHERE {
  BIND(<http://api.koneksys.com/cameo/TMT/instance%20specification/_18_0_6_baa02e2_1488148798111_288113_188699> AS ?inst)

  OPTIONAL { ?inst vocab:NamedElement_name ?instName . }
  OPTIONAL {
    ?inst vocab:InstanceSpecification_specification ?spec .
    OPTIONAL { ?spec vocab:NamedElement_name ?specName . }
  }

  OPTIONAL {
    ?inst vocab:InstanceSpecification_slot ?slot .
    ?slot rdf:type ?slotType .
    OPTIONAL { ?slot vocab:NamedElement_name ?slotValueName . }
  }
}
LIMIT 25
